// =============================================================================
// categorizeAction
// =============================================================================

describe('categorizeAction', () => {
  it.each([
    ['Read', undefined, 'exploration'],
    ['Glob', undefined, 'exploration'],
    ['Grep', undefined, 'exploration'],
  ] as const)('%s => %s', (tool, cmd, expected) => {
    expect(categorizeAction(tool, cmd)).toBe(expected);
  });

  it.each([
    ['Write', 'modification'],
    ['Edit', 'modification'],
    ['MultiEdit', 'modification'],
    ['NotebookEdit', 'modification'],
  ] as const)('%s => %s', (tool, expected) => {
    expect(categorizeAction(tool)).toBe(expected);
  });

  it('returns agent for Task tool', () => {
    expect(categorizeAction('Task')).toBe('agent');
  });

  it('returns testing for Bash test commands', () => {
    expect(categorizeAction('Bash', 'npm test')).toBe('testing');
    expect(categorizeAction('Bash', 'pytest tests/')).toBe('testing');
    expect(categorizeAction('Bash', 'vitest run')).toBe('testing');
    expect(categorizeAction('Bash', 'jest --watch')).toBe('testing');
  });

  it('returns building for Bash build commands', () => {
    expect(categorizeAction('Bash', 'npm run build')).toBe('building');
    expect(categorizeAction('Bash', 'tsc --noEmit')).toBe('building');
    expect(categorizeAction('Bash', 'cargo build')).toBe('building');
  });

  it('returns git for git commands', () => {
    expect(categorizeAction('Bash', 'git commit -m "msg"')).toBe('git');
    expect(categorizeAction('Bash', 'git status')).toBe('git');
    expect(categorizeAction('Bash', 'gh pr create')).toBe('git');
  });

  it('returns execution for generic Bash commands', () => {
    expect(categorizeAction('Bash', 'ls -la')).toBe('execution');
    expect(categorizeAction('Bash', 'curl http://example.com')).toBe('execution');
  });

  it('returns other for unknown tools', () => {
    expect(categorizeAction('UnknownTool')).toBe('other');
  });

  it('returns execution for Bash with no command', () => {
    // Bash tool present but command is undefined — falls through to 'other'
    // because the if-guard checks `tool === 'Bash' && command`
    expect(categorizeAction('Bash')).toBe('other');
  });
});

// =============================================================================
// summarizeAction
// =============================================================================

describe('summarizeAction', () => {
  it('summarizes Read with file basename', () => {
    expect(summarizeAction('Read', undefined, '/path/to/file.ts', 'success')).toBe('✓ Read file.ts');
  });

  it('summarizes Read with no file', () => {
    expect(summarizeAction('Read', undefined, undefined, 'failure')).toBe('✗ Read file');
  });

  it('summarizes Write', () => {
    expect(summarizeAction('Write', undefined, '/a/b.py', 'success')).toBe('✓ Write b.py');
  });

  it('summarizes Edit', () => {
    expect(summarizeAction('Edit', undefined, '/a/b.py', 'partial')).toBe('~ Edit b.py');
  });

  it('summarizes Glob', () => {
    expect(summarizeAction('Glob')).toContain('Search files');
  });

  it('summarizes Grep', () => {
    expect(summarizeAction('Grep')).toContain('Search content');
  });

  it('summarizes Task', () => {
    expect(summarizeAction('Task')).toContain('Spawn agent');
  });

  it('summarizes Bash with short command', () => {
    const result = summarizeAction('Bash', 'echo hello', undefined, 'success');
    expect(result).toBe('✓ echo hello');
  });

  it('truncates long Bash commands', () => {
    const longCmd = 'a'.repeat(60);
    const result = summarizeAction('Bash', longCmd, undefined, 'success');
    expect(result).toContain('...');
    // First line, sliced to 50 chars
    expect(result).toContain('a'.repeat(50));
  });

  it('uses first line of multi-line Bash command', () => {
    const result = summarizeAction('Bash', 'line1\nline2\nline3', undefined, 'success');
    expect(result).toContain('line1');
    expect(result).not.toContain('line2');
  });

  it('summarizes unknown tool', () => {
    expect(summarizeAction('FooTool', undefined, undefined, 'failure')).toBe('✗ FooTool');
  });

  it('defaults to success symbol when result is undefined', () => {
    const result = summarizeAction('Glob');
    expect(result).toContain('~'); // undefined result maps to '~'
  });
});

// =============================================================================
// inferWorkflowPattern
