describe('inferWorkflowPattern', () => {
  it('returns mixed for fewer than 3 actions', () => {
    expect(inferWorkflowPattern([])).toBe('mixed');
    expect(inferWorkflowPattern([makeAction(), makeAction()])).toBe('mixed');
  });

  it('detects test-first pattern', () => {
    // test -> write -> test
    const actions: ToolAction[] = [
      makeAction({ category: 'testing' }),
      makeAction({ category: 'modification' }),
      makeAction({ category: 'testing' }),
    ];
    expect(inferWorkflowPattern(actions)).toBe('test-first');
  });

  it('detects explore-first pattern', () => {
    // read -> read -> read -> write
    const actions: ToolAction[] = [
      makeAction({ category: 'exploration' }),
      makeAction({ category: 'exploration' }),
      makeAction({ category: 'exploration' }),
      makeAction({ category: 'modification' }),
    ];
    expect(inferWorkflowPattern(actions)).toBe('explore-first');
  });

  it('detects iterate-fast pattern', () => {
    // write -> execute -> write -> execute
    const actions: ToolAction[] = [
      makeAction({ category: 'modification' }),
      makeAction({ category: 'execution' }),
      makeAction({ category: 'modification' }),
      makeAction({ category: 'execution' }),
    ];
    expect(inferWorkflowPattern(actions)).toBe('iterate-fast');
  });

  it('detects agent-delegate pattern with 3+ agent actions', () => {
    const actions: ToolAction[] = [
      makeAction({ category: 'agent' }),
      makeAction({ category: 'agent' }),
      makeAction({ category: 'agent' }),
    ];
    expect(inferWorkflowPattern(actions)).toBe('agent-delegate');
  });

  it('detects agent-delegate pattern by ratio > 0.3', () => {
    const actions: ToolAction[] = [
      makeAction({ category: 'agent' }),
      makeAction({ category: 'agent' }),
      makeAction({ category: 'exploration' }),
      makeAction({ category: 'exploration' }),
      makeAction({ category: 'exploration' }),
    ];
    // 2/5 = 0.4 > 0.3
    expect(inferWorkflowPattern(actions)).toBe('agent-delegate');
  });

  it('detects big-bang pattern', () => {
    // write -> write -> write -> test (test near end)
    const actions: ToolAction[] = [
      makeAction({ category: 'modification' }),
      makeAction({ category: 'modification' }),
      makeAction({ category: 'modification' }),
      makeAction({ category: 'testing' }),
    ];
    expect(inferWorkflowPattern(actions)).toBe('big-bang');
  });

  it('returns mixed when no pattern matches', () => {
    const actions: ToolAction[] = [
      makeAction({ category: 'other' }),
      makeAction({ category: 'git' }),
      makeAction({ category: 'other' }),
    ];
    expect(inferWorkflowPattern(actions)).toBe('mixed');
  });
});

