describe('trackToolAction', () => {
  beforeEach(() => {
    // Ensure clean state
    try { fs.rmSync('/tmp/fake-project/.claude/memory/flows', { recursive: true, force: true }); } catch {}
  });

  it('creates a new flow when none exists', () => {
    const flow = trackToolAction('new-session', 'Read', undefined, '/a/b.ts', undefined);
    expect(flow.session_id).toBe('new-session');
    expect(flow.actions).toHaveLength(1);
    expect(flow.actions[0].tool).toBe('Read');
    expect(flow.actions[0].category).toBe('exploration');
    expect(flow.stats.total_actions).toBe(1);
    expect(flow.stats.reads).toBe(1);
  });

  it('appends to existing flow', () => {
    trackToolAction('append-session', 'Read', undefined, '/a.ts', undefined);
    const flow = trackToolAction('append-session', 'Write', undefined, '/b.ts', undefined);
    expect(flow.actions).toHaveLength(2);
    expect(flow.stats.reads).toBe(1);
    expect(flow.stats.writes).toBe(1);
  });

  it('determines failure from non-zero exit code', () => {
    const flow = trackToolAction('fail-session', 'Bash', 'npm test', undefined, 1);
    expect(flow.actions[0].result).toBe('failure');
    expect(flow.actions[0].exit_code).toBe(1);
  });

  it('determines success from zero exit code', () => {
    const flow = trackToolAction('ok-session', 'Bash', 'echo hi', undefined, 0);
    expect(flow.actions[0].result).toBe('success');
  });

  it('caps actions at 100', () => {
    for (let i = 0; i < 105; i++) {
      trackToolAction('cap-session', 'Read', undefined, `/file${i}.ts`, undefined);
    }
    const flow = trackToolAction('cap-session', 'Read', undefined, '/last.ts', undefined);
    expect(flow.actions.length).toBeLessThanOrEqual(100);
  });

  it('updates inferred_pattern and stats', () => {
    trackToolAction('pattern-session', 'Read', undefined, '/a.ts', undefined);
    trackToolAction('pattern-session', 'Read', undefined, '/b.ts', undefined);
    trackToolAction('pattern-session', 'Read', undefined, '/c.ts', undefined);
    const flow = trackToolAction('pattern-session', 'Write', undefined, '/d.ts', undefined);
    expect(flow.inferred_pattern).toBe('explore-first');
    expect(flow.stats.success_rate).toBe(1);
  });
});

